 1	import React, { FC, ReactNode } from 'react';
 2	
 3	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 4	import {
 5	  Breadcrumb,
 6	  BreadcrumbItem,
 7	  DescriptionListTerm,
 8	  DescriptionListTermHelpTextButton,
 9	  Popover,
10	} from '@patternfly/react-core';
11	
12	import './DescriptionItem.scss';
13	
14	type DescriptionItemHeaderProps = {
15	  bodyContent: ReactNode;
16	  breadcrumb?: string;
17	  descriptionHeader: ReactNode;
18	  isPopover: boolean;
19	  label?: ReactNode;
20	  maxWidth?: string;
21	  moreInfoURL?: string;
22	};
23	
24	export const DescriptionItemHeader: FC<DescriptionItemHeaderProps> = ({
25	  bodyContent,
26	  breadcrumb,
27	  descriptionHeader,
28	  isPopover,
29	  label,
30	  maxWidth,
31	  moreInfoURL,
32	}) => {
33	  const { t } = useKubevirtTranslation();
34	
35	  if (isPopover && bodyContent) {
36	    return (
37	      <Popover
38	        bodyContent={
39	          <>
40	            {bodyContent}
41	            {moreInfoURL && (
42	              <>
43	                {t('More info: ')}
44	                <a href={moreInfoURL}>{moreInfoURL}</a>
45	              </>
46	            )}
47	            {breadcrumb && (
48	              <div className="margin-top">
49	                <Breadcrumb>
50	                  {breadcrumb.split('.').map((item) => (
51	                    <BreadcrumbItem key={item}>{item}</BreadcrumbItem>
52	                  ))}
53	                </Breadcrumb>
54	              </div>
55	            )}
56	          </>
57	        }
58	        hasAutoWidth
59	        headerContent={descriptionHeader}
60	        maxWidth={maxWidth || '30rem'}
61	      >
62	        <DescriptionListTermHelpTextButton className="pf-v6-c-description-list__text">
63	          {descriptionHeader}
64	        </DescriptionListTermHelpTextButton>
65	      </Popover>
66	    );
67	  }
68	
69	  return (
70	    <DescriptionListTerm className="DescriptionItemHeader--list-term">
71	      {descriptionHeader} {label}
72	    </DescriptionListTerm>
73	  );
74	};

